                unixDateParam.ParameterName = "@unixDate";
                unixDateParam.Value = today.ToString("yyyy-MM-dd");
                command.Parameters.Add(unixDateParam);

                command.ExecuteNonQuery();
            }
        }
        catch (Exception e) {
